static public PrintMgmtIdentificationTxt ReturnFooter_NodeTypeSales(PrintMgmtDocumentType _PrintMgmtDocumentType, LanguageId _LanguageId)
{
    PrintMgmtDocInstance        printMgmtDocInstance;
    PrintMgmtSettings           printMgmtSettings;
    PrintMgmtIdentificationText printMgmtIdentificationText;

    Select printMgmtDocInstance
        where printMgmtDocInstance.DocumentType == _PrintMgmtDocumentType
           && printMgmtDocInstance.NodeType == PrintMgmtNodeType::Sales
           && printMgmtDocInstance.PrintType == PrintMgmtDocInstanceType::Original
        join printMgmtSettings
        where printMgmtSettings.ParentId == printMgmtDocInstance.RecId
        join printMgmtIdentificationText
        where printMgmtIdentificationText.ParentId == printMgmtSettings.ParentId
        && printMgmtIdentificationText.LanguageId == _LanguageId;

    return printMgmtIdentificationText.IdentificationText;
}

static public PrintMgmtIdentificationTxt ReturnFooter_NodeTypePurch(PrintMgmtDocumentType _PrintMgmtDocumentType, LanguageId _LanguageId)
{
    PrintMgmtDocInstance        printMgmtDocInstance;
    PrintMgmtSettings           printMgmtSettings;
    PrintMgmtIdentificationText printMgmtIdentificationText;

    Select printMgmtDocInstance
        where printMgmtDocInstance.DocumentType == _PrintMgmtDocumentType
           && printMgmtDocInstance.NodeType == PrintMgmtNodeType::Purch
           && printMgmtDocInstance.PrintType == PrintMgmtDocInstanceType::Original
        join printMgmtSettings
        where printMgmtSettings.ParentId == printMgmtDocInstance.RecId
        join printMgmtIdentificationText
        where printMgmtIdentificationText.ParentId == printMgmtSettings.ParentId
        && printMgmtIdentificationText.LanguageId == _LanguageId;

    return printMgmtIdentificationText.IdentificationText;
}
